// generar_261_hitos_cachorro.js
// CHIQUI Entre Señales — Hitos de cachorro/gatito
//
// IMPORTANTE: primero corre sql_261_hitos_cachorro.sql en Supabase
// (New snippet) — crea la tabla hitos_cachorro con RLS y la
// restricción UNIQUE(mascota_id, hito) que garantiza que cada hito se
// registre una sola vez.
//
// NOTA: este script escribe app/registro-diario/page.tsx completo e
// incluye también los cambios del generar_260 (enriquecimiento y
// mejoras de cuidados). Corre el 260 y su SQL ANTES de este (o al
// menos su SQL), para que ambos features queden operativos.
//
// Qué agrega:
//
// 🐾 SECCIÓN "HITOS DE CACHORRO / HITOS DE GATITO" en el registro
// diario, visible SOLO para mascotas menores de 1 año con fecha de
// nacimiento conocida (mismo umbral "Cachorro" de calcularEtapaVida,
// validado con veterinario). Al cumplir el año, la sección desaparece
// sola — pero los hitos quedan guardados para siempre.
//
// Hitos comunes (ambas especies):
//   🦷 Se le cayó su primer diente de leche
//   😁 Le salió su primer diente definitivo
//   💉 Completó sus primeras vacunas
//   📛 Responde a su nombre
//   🌙 Primera noche durmiendo completa
// Solo perros:
//   🦮 Su primer paseo en la calle
//   ✅ Aprendió a hacer sus necesidades donde corresponde
//   🐶 Conoció a otro perro por primera vez
// Solo gatos:
//   🧹 Usó el arenero solo por primera vez
//   😺 Su primer ronroneo contigo
//   🪟 Exploró toda la casa por primera vez
//
// Comportamiento:
// - La sección aparece al final de "Cuidados de hoy" con borde dorado
//   y contador de progreso (ej. "3/8") — gamificación suave que
//   incentiva completar el álbum del primer año.
// - Tocar un hito lo registra AL TIRO con la fecha del registro
//   actual (escritura inmediata, no espera al botón Guardar: un hito
//   es un momento y merece quedar grabado al instante). El chip se
//   pone dorado y muestra la fecha para siempre.
// - Tocar un hito ya logrado lo desmarca (solo para corregir errores).
// - Cada hito es único por mascota (UNIQUE en base).
//
// Uso:
//   1) SQL primero: sql_261_hitos_cachorro.sql → Run
//   2) node generar_261_hitos_cachorro.js
//   3) git add . && commit && push

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: 'app/registro-diario/page.tsx',
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 1 archivo escrito (incluye 260 + 261).')
  console.log('Recuerda: SQL primero, luego git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
